A simpler test case:

#include <netinet/in.h>
#include <resolv.h>

int main (int argc, char *argv[]) {
    if (argc < 2) return 1;
    int ret = res_hnok(argv[1]);
    printf("%d\n", ret);
}

Usage:

landonf:~> ./test-res_hnok gc._msdcs.example.org
0

landonf:~> ./test-res_hnok gc.msdcs.example.org 
1
